THOUGHT: The miscompile occurs when InstCombine canonicalizes a select-of-fcmp into maxnum/minnum, which unconditionally evaluates the operand and becomes poison with ninf when the variable is -inf. Broadly disabling the transform for all ninf broke tests. To minimize impact, I will restrict the guard to the specific problematic case: when hasNoInfs is set and one of the operands is a zero constant. That matches the reproducer (max(%in, 0)). I’ll add a check to skip creating maxnum/minnum if ninf is present and either operand is zero, avoiding the miscompile while preserving other optimizations.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@
-    if (SIFPOp->hasNoNaNs() && SIFPOp->hasNoSignedZeros()) {
+    if (SIFPOp->hasNoNaNs() && SIFPOp->hasNoSignedZeros()) {
       Value *X, *Y;
       if (match(&SI, m_OrdOrUnordFMax(m_Value(X), m_Value(Y)))) {
+        // Avoid canonicalizing to maxnum when fast-math disallows infinities
+        // and one operand is zero. This can turn a previously guarded -inf
+        // (which would not be selected) into unconditional poison by evaluating
+        // the maxnum unconditionally.
+        if (SIFPOp->hasNoInfs() &&
+            (match(X, m_AnyZeroFP()) || match(Y, m_AnyZeroFP())))
+          return nullptr;
         Value *BinIntr =
             Builder.CreateBinaryIntrinsic(Intrinsic::maxnum, X, Y, &SI);
         if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr))
           BinIntrInst->setHasNoNaNs(FCmp->hasNoNaNs());
         return replaceInstUsesWith(SI, BinIntr);
       }

       if (match(&SI, m_OrdOrUnordFMin(m_Value(X), m_Value(Y)))) {
+        // Avoid canonicalizing to minnum when fast-math disallows infinities
+        // and one operand is zero for the same poison-safety reason as above.
+        if (SIFPOp->hasNoInfs() &&
+            (match(X, m_AnyZeroFP()) || match(Y, m_AnyZeroFP())))
+          return nullptr;
         Value *BinIntr =
             Builder.CreateBinaryIntrinsic(Intrinsic::minnum, X, Y, &SI);
         if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr))
           BinIntrInst->setHasNoNaNs(FCmp->hasNoNaNs());
         return replaceInstUsesWith(SI, BinIntr);
*** End Patch
EOF
```

